	}
	if cfg.Params.Temperature != 0.7 {
		t.Errorf("Params.Temperature = %f, want 0.7", cfg.Params.Temperature)
	}
	if cfg.Params.MaxTokens != 4096 {
		t.Errorf("Params.MaxTokens = %d, want 4096", cfg.Params.MaxTokens)
